// The user has handed me a mix of material — notes, a spreadsheet, a PDF, a photo, and a voice
// memo — all about their Tanzania trip. I need to read ALL of it: the notes/spreadsheet/booklet
// through `system-files`, the photo through `system-vision`, and I already have the transcript.
// Let me fire all three delegates in parallel so I can form a complete picture.
const [fileAnswer, photoAnswer] = await Promise.all([
  delegate('system-files', 'dispatch', {
    query: 'Summarize these three documents — what trip details, costs, dates, names, and figures does each one contain? List every distinct dataset (sheets in the workbook, sections in the notes, tariff tables in the PDF) with the key facts from each.',
    attachmentIds: ['e64bbfba-bb05-4748-ba7e-10238318bd4f', 'e89f53ed-8952-4135-b478-c31de6db699b', '1a453246-5780-4f4a-a2a2-f2b71d55c38e'],
  }) as string,
  delegate('system-vision', 'vision', {
    query: 'Describe this photo in a few sentences — what is shown, where it appears to be, any notable detail. This is for trip-organizing context, not a full image description.',
    attachmentIds: ['08be06e4-34ff-428b-b72a-e9928f9f0adf'],
  }) as string,
]);
